begin;
alter table public.contacts add column if not exists first_name text;alter table public.contacts add column if not exists last_name text;alter table public.contacts add column if not exists job_title text;alter table public.contacts add column if not exists company_id uuid;alter table public.contacts add column if not exists source text not null default 'manual';alter table public.contacts add column if not exists notes text;alter table public.contacts add column if not exists updated_at timestamptz not null default now();
create table if not exists public.companies(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,name text not null,website text,industry text,phone text,address text,notes text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
alter table public.contacts add constraint contacts_company_fk foreign key(company_id) references public.companies(id) on delete set null;
create table if not exists public.opportunities(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,company_id uuid references public.companies(id) on delete set null,primary_contact_id uuid references public.contacts(id) on delete set null,title text not null,value numeric,currency text not null default 'USD',stage text not null default 'lead',probability integer,expected_close_at timestamptz,source text not null default 'manual',notes text,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),check(stage in('lead','contacted','qualified','proposal','negotiation','won','lost')));
create table if not exists public.crm_activities(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,contact_id uuid references public.contacts(id) on delete cascade,company_id uuid references public.companies(id) on delete cascade,opportunity_id uuid references public.opportunities(id) on delete cascade,activity_type text not null,content text not null,occurred_at timestamptz not null default now(),created_at timestamptz not null default now());
alter table public.companies enable row level security;alter table public.opportunities enable row level security;alter table public.crm_activities enable row level security;alter table public.contacts enable row level security;
create policy "Users manage own companies" on public.companies for all to authenticated using(user_id=auth.uid()) with check(user_id=auth.uid());create policy "Users manage own opportunities" on public.opportunities for all to authenticated using(user_id=auth.uid()) with check(user_id=auth.uid());create policy "Users manage own crm activities" on public.crm_activities for all to authenticated using(user_id=auth.uid()) with check(user_id=auth.uid());
create index if not exists opportunities_user_stage_idx on public.opportunities(user_id,stage);create index if not exists contacts_user_name_idx on public.contacts(user_id,name);
commit;
